use crate::decoders::{Crack, CrackResult, Decoder, check_string_success};use crate::checkers::CheckerTypes;use std::marker::PhantomData;pub struct UrlDecoder;impl Crack for Decoder<UrlDecoder> {    fn crack(&self, text: &str, checker: &CheckerTypes) -> CrackResult {        let mut result = CrackResult::new(self.get_name(), self.get_description(), self.get_link());        result.encrypted_text = text.to_string();        if let Ok(decoded_str) = urlencoding::decode(text) {            let decoded = decoded_str.to_string();            if check_string_success(&decoded, text) {                let check_result = checker.check_text(&decoded);                if check_result.is_identified {                    result.success = true;                    result.unencrypted_text = Some(vec![decoded]);                    result.checker_name = check_result.checker_name;                }            }        }        result    }    fn get_name(&self) -> &'static str { "URL" }    fn get_popularity(&self) -> f32 { 0.6 }    fn get_tags(&self) -> &'static [&'static str] { &["url", "decoder", "encoding"] }    fn get_description(&self) -> &'static str { "URL encoding (percent-encoding) is a mechanism for encoding information in a URI." }    fn get_link(&self) -> &'static str { "https://en.wikipedia.org/wiki/Percent-encoding" }}impl Decoder<UrlDecoder> {    pub fn new() -> Self {        Decoder {            name: "URL",            description: "URL encoding (percent-encoding) is a mechanism for encoding information in a URI.",            link: "https://en.wikipedia.org/wiki/Percent-encoding",            tags: vec!["url", "decoder", "encoding"],            popularity: 0.6,            phantom: PhantomData,        }    }}



